package com.example.oidcclient.service;

import com.example.oidcclient.model.UserSession;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.core.GrantedAuthority;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.oauth2.client.oidc.userinfo.OidcUserRequest;
import org.springframework.security.oauth2.client.oidc.userinfo.OidcUserService;
import org.springframework.security.oauth2.client.userinfo.OAuth2UserService;
import org.springframework.security.oauth2.core.OAuth2AuthenticationException;
import org.springframework.security.oauth2.core.OAuth2Error;
import org.springframework.security.oauth2.core.oidc.OidcIdToken;
import org.springframework.security.oauth2.core.oidc.OidcUserInfo;
import org.springframework.security.oauth2.core.oidc.user.DefaultOidcUser;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.stereotype.Service;

import java.time.Instant;
import java.util.*;

@Service
public class CustomOidcUserService implements OAuth2UserService<OidcUserRequest, OidcUser> {

    private static final Logger logger = LoggerFactory.getLogger(CustomOidcUserService.class);

    private final OidcUserService delegate = new OidcUserService();
    private final UserSessionService userSessionService;
    private final IdTokenClaimsParser idTokenClaimsParser;

    public CustomOidcUserService(UserSessionService userSessionService,
                                  IdTokenClaimsParser idTokenClaimsParser) {
        this.userSessionService = userSessionService;
        this.idTokenClaimsParser = idTokenClaimsParser;
    }

    @Override
    public OidcUser loadUser(OidcUserRequest userRequest) throws OAuth2AuthenticationException {
        OidcUser oidcUser = delegate.loadUser(userRequest);

        logger.info("Loading OIDC user: {}", oidcUser.getSubject());

        try {
            // Parse ID token claims
            OidcIdToken idToken = userRequest.getIdToken();
            Map<String, Object> claims = idTokenClaimsParser.parseClaims(idToken);

            // Validate token
            validateIdToken(idToken, userRequest);

            // Extract authorities from claims
            Set<GrantedAuthority> authorities = extractAuthorities(claims);
            authorities.addAll(oidcUser.getAuthorities());

            // Create user session
            UserSession userSession = createUserSession(oidcUser, idToken, userRequest);
            userSessionService.saveSession(userSession);

            logger.info("User session created for subject: {}, email: {}",
                userSession.getSubject(), userSession.getEmail());

            // Return enhanced OidcUser with additional authorities
            return new DefaultOidcUser(
                authorities,
                oidcUser.getIdToken(),
                oidcUser.getUserInfo(),
                "sub"
            );

        } catch (OAuth2AuthenticationException ex) {
            throw ex;
        } catch (Exception ex) {
            logger.error("Error processing OIDC user", ex);
            throw new OAuth2AuthenticationException(
                new OAuth2Error("user_processing_error", "Failed to process user: " + ex.getMessage(), null));
        }
    }

    private void validateIdToken(OidcIdToken idToken, OidcUserRequest userRequest) {
        Instant now = Instant.now();

        // Validate expiration
        if (idToken.getExpiresAt() != null && idToken.getExpiresAt().isBefore(now)) {
            throw new OAuth2AuthenticationException(
                new OAuth2Error("invalid_id_token", "ID token has expired", null));
        }

        // Validate audience
        List<String> audience = idToken.getAudience();
        String clientId = userRequest.getClientRegistration().getClientId();
        if (audience != null && !audience.contains(clientId)) {
            throw new OAuth2AuthenticationException(
                new OAuth2Error("invalid_id_token", "ID token audience does not match client ID", null));
        }

        logger.debug("ID token validation passed for subject: {}", idToken.getSubject());
    }

    private Set<GrantedAuthority> extractAuthorities(Map<String, Object> claims) {
        Set<GrantedAuthority> authorities = new HashSet<>();
        authorities.add(new SimpleGrantedAuthority("ROLE_USER"));

        // Extract roles from claims (common patterns)
        Object rolesClaim = claims.get("roles");
        if (rolesClaim == null) {
            rolesClaim = claims.get("realm_access");
        }
        if (rolesClaim == null) {
            rolesClaim = claims.get("groups");
        }

        if (rolesClaim instanceof Collection<?>) {
            ((Collection<?>) rolesClaim).forEach(role -> {
                String roleStr = role.toString().toUpperCase();
                if (!roleStr.startsWith("ROLE_")) {
                    roleStr = "ROLE_" + roleStr;
                }
                authorities.add(new SimpleGrantedAuthority(roleStr));
            });
        } else if (rolesClaim instanceof Map) {
            @SuppressWarnings("unchecked")
            Map<String, Object> realmAccess = (Map<String, Object>) rolesClaim;
            Object roles = realmAccess.get("roles");
            if (roles instanceof Collection<?>) {
                ((Collection<?>) roles).forEach(role -> {
                    String roleStr = role.toString().toUpperCase();
                    if (!roleStr.startsWith("ROLE_")) {
                        roleStr = "ROLE_" + roleStr;
                    }
                    authorities.add(new SimpleGrantedAuthority(roleStr));
                });
            }
        }

        return authorities;
    }

    private UserSession createUserSession(OidcUser oidcUser, OidcIdToken idToken,
                                           OidcUserRequest userRequest) {
        UserSession session = new UserSession();
        session.setSessionId(UUID.randomUUID().toString());
        session.setSubject(idToken.getSubject());
        session.setIssuer(idToken.getIssuer() != null ? idToken.getIssuer().toString() : null);
        session.setEmail(idToken.getEmail());
        session.setEmailVerified(idToken.getEmailVerified());
        session.setFullName(idToken.getFullName());
        session.setGivenName(idToken.getGivenName());
        session.setFamilyName(idToken.getFamilyName());
        session.setPreferredUsername(idToken.getClaimAsString("preferred_username"));
        session.setPicture(idToken.getPicture() != null ? idToken.getPicture().toString() : null);
        session.setLocale(idToken.getLocale());
        session.setIssuedAt(idToken.getIssuedAt());
        session.setExpiresAt(idToken.getExpiresAt());
        session.setAuthenticatedAt(idToken.getAuthenticatedAt());
        session.setNonce(idToken.getNonce());
        session.setAccessTokenValue(userRequest.getAccessToken().getTokenValue());
        session.setIdTokenValue(idToken.getTokenValue());
        session.setCreatedAt(Instant.now());

        // Store additional claims
        Map<String, Object> additionalClaims = new HashMap<>(idToken.getClaims());
        session.setAdditionalClaims(additionalClaims);

        // Extract UserInfo if available
        OidcUserInfo userInfo = oidcUser.getUserInfo();
        if (userInfo != null) {
            session.setUserInfoClaims(userInfo.getClaims());
        }

        return session;
    }
}

