package com.example.oidcclient.service;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.oauth2.core.oidc.OidcIdToken;
import org.springframework.stereotype.Service;

import java.time.Instant;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

@Service
public class IdTokenClaimsParser {

    private static final Logger logger = LoggerFactory.getLogger(IdTokenClaimsParser.class);

    public Map<String, Object> parseClaims(OidcIdToken idToken) {
        Map<String, Object> parsedClaims = new HashMap<>();

        if (idToken == null || idToken.getClaims() == null) {
            logger.warn("ID token or claims are null");
            return parsedClaims;
        }

        Map<String, Object> claims = idToken.getClaims();

        // Standard OIDC claims
        parsedClaims.put("sub", idToken.getSubject());
        parsedClaims.put("iss", idToken.getIssuer() != null ? idToken.getIssuer().toString() : null);
        parsedClaims.put("aud", idToken.getAudience());
        parsedClaims.put("exp", idToken.getExpiresAt());
        parsedClaims.put("iat", idToken.getIssuedAt());
        parsedClaims.put("auth_time", idToken.getAuthenticatedAt());
        parsedClaims.put("nonce", idToken.getNonce());
        parsedClaims.put("acr", idToken.getClaimAsString("acr"));
        parsedClaims.put("amr", idToken.getClaimAsStringList("amr"));
        parsedClaims.put("azp", idToken.getAuthorizedParty());

        // Profile claims
        parsedClaims.put("name", idToken.getFullName());
        parsedClaims.put("given_name", idToken.getGivenName());
        parsedClaims.put("family_name", idToken.getFamilyName());
        parsedClaims.put("middle_name", idToken.getMiddleName());
        parsedClaims.put("nickname", idToken.getNickName());
        parsedClaims.put("preferred_username", idToken.getPreferredUsername());
        parsedClaims.put("profile", idToken.getProfile() != null ? idToken.getProfile().toString() : null);
        parsedClaims.put("picture", idToken.getPicture() != null ? idToken.getPicture().toString() : null);
        parsedClaims.put("website", idToken.getWebsite() != null ? idToken.getWebsite().toString() : null);
        parsedClaims.put("gender", idToken.getGender());
        parsedClaims.put("birthdate", idToken.getBirthdate());
        parsedClaims.put("zoneinfo", idToken.getZoneInfo());
        parsedClaims.put("locale", idToken.getLocale());
        parsedClaims.put("updated_at", idToken.getUpdatedAt());

        // Email claims
        parsedClaims.put("email", idToken.getEmail());
        parsedClaims.put("email_verified", idToken.getEmailVerified());

        // Phone claims
        parsedClaims.put("phone_number", idToken.getPhoneNumber());
        parsedClaims.put("phone_number_verified", idToken.getPhoneNumberVerified());

        // Address claim
        if (idToken.getAddress() != null) {
            parsedClaims.put("address", idToken.getAddress().getClaims());
        }

        // Custom/additional claims
        for (Map.Entry<String, Object> entry : claims.entrySet()) {
            if (!parsedClaims.containsKey(entry.getKey())) {
                parsedClaims.put(entry.getKey(), entry.getValue());
                logger.debug("Additional claim found: {} = {}", entry.getKey(), entry.getValue());
            }
        }

        // Remove null values
        parsedClaims.entrySet().removeIf(entry -> entry.getValue() == null);

        logger.info("Parsed {} claims from ID token for subject: {}",
            parsedClaims.size(), idToken.getSubject());

        return parsedClaims;
    }

    public boolean isTokenExpired(OidcIdToken idToken) {
        Instant expiresAt = idToken.getExpiresAt();
        return expiresAt != null && expiresAt.isBefore(Instant.now());
    }

    public List<String> getAudience(OidcIdToken idToken) {
        return idToken.getAudience();
    }

    public String getIssuer(OidcIdToken idToken) {
        return idToken.getIssuer() != null ? idToken.getIssuer().toString() : null;
    }
}

