package com.example.oidcclient.service;

import com.example.oidcclient.model.UserSession;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

import java.time.Instant;
import java.util.Map;
import java.util.Optional;
import java.util.concurrent.ConcurrentHashMap;

@Service
public class UserSessionService {

    private static final Logger logger = LoggerFactory.getLogger(UserSessionService.class);

    // In production, use Redis or a database
    private final Map<String, UserSession> sessionStore = new ConcurrentHashMap<>();
    private final Map<String, String> subjectToSessionMap = new ConcurrentHashMap<>();

    public void saveSession(UserSession session) {
        session.setLastAccessedAt(Instant.now());

        // Remove existing session for the same subject
        String existingSessionId = subjectToSessionMap.get(session.getSubject());
        if (existingSessionId != null) {
            sessionStore.remove(existingSessionId);
            logger.info("Removed existing session {} for subject {}", existingSessionId, session.getSubject());
        }

        sessionStore.put(session.getSessionId(), session);
        subjectToSessionMap.put(session.getSubject(), session.getSessionId());

        logger.info("Session saved: {} for subject: {}", session.getSessionId(), session.getSubject());
    }

    public Optional<UserSession> getSession(String sessionId) {
        UserSession session = sessionStore.get(sessionId);
        if (session != null) {
            session.setLastAccessedAt(Instant.now());
            if (session.isExpired()) {
                removeSession(sessionId);
                logger.info("Session {} has expired, removed", sessionId);
                return Optional.empty();
            }
        }
        return Optional.ofNullable(session);
    }

    public Optional<UserSession> getSessionBySubject(String subject) {
        String sessionId = subjectToSessionMap.get(subject);
        if (sessionId != null) {
            return getSession(sessionId);
        }
        return Optional.empty();
    }

    public void removeSession(String sessionId) {
        UserSession session = sessionStore.remove(sessionId);
        if (session != null) {
            subjectToSessionMap.remove(session.getSubject());
            logger.info("Session removed: {} for subject: {}", sessionId, session.getSubject());
        }
    }

    public void removeSessionBySubject(String subject) {
        String sessionId = subjectToSessionMap.remove(subject);
        if (sessionId != null) {
            sessionStore.remove(sessionId);
            logger.info("Session removed for subject: {}", subject);
        }
    }

    public int getActiveSessionCount() {
        return sessionStore.size();
    }

    public void cleanExpiredSessions() {
        sessionStore.entrySet().removeIf(entry -> {
            if (entry.getValue().isExpired()) {
                subjectToSessionMap.remove(entry.getValue().getSubject());
                logger.info("Cleaned expired session: {}", entry.getKey());
                return true;
            }
            return false;
        });
    }
}

