// Token Exchange Service
// ============================================================
package com.example.oidcclient.service;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.*;
import org.springframework.security.oauth2.client.registration.ClientRegistration;
import org.springframework.security.oauth2.client.registration.ClientRegistrationRepository;
import org.springframework.stereotype.Service;
import org.springframework.util.LinkedMultiValueMap;
import org.springframework.util.MultiValueMap;
import org.springframework.web.client.RestTemplate;

import java.util.Base64;
import java.util.Map;

@Service
public class TokenExchangeService {

    private static final Logger logger = LoggerFactory.getLogger(TokenExchangeService.class);

    private final ClientRegistrationRepository clientRegistrationRepository;
    private final RestTemplate restTemplate;

    public TokenExchangeService(ClientRegistrationRepository clientRegistrationRepository) {
        this.clientRegistrationRepository = clientRegistrationRepository;
        this.restTemplate = new RestTemplate();
    }

    /**
     * Exchange an authorization code for tokens at the token endpoint.
     */
    public Map<String, Object> exchangeAuthorizationCode(String code, String redirectUri,
                                                          String registrationId) {
        ClientRegistration registration = clientRegistrationRepository.findByRegistrationId(registrationId);
        if (registration == null) {
            throw new IllegalArgumentException("Unknown registration: " + registrationId);
        }

        String tokenUri = registration.getProviderDetails().getTokenUri();
        String clientId = registration.getClientId();
        String clientSecret = registration.getClientSecret();

        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.APPLICATION_FORM_URLENCODED);

        // Use Basic authentication for client credentials
        String credentials = Base64.getEncoder().encodeToString((clientId + ":" + clientSecret).getBytes());
        headers.set("Authorization", "Basic " + credentials);

        MultiValueMap<String, String> body = new LinkedMultiValueMap<>();
        body.add("grant_type", "authorization_code");
        body.add("code", code);
        body.add("redirect_uri", redirectUri);

        HttpEntity<MultiValueMap<String, String>> request = new HttpEntity<>(body, headers);

        logger.info("Exchanging authorization code at token endpoint: {}", tokenUri);

        try {
            @SuppressWarnings("unchecked")
            ResponseEntity<Map> response = restTemplate.exchange(tokenUri, HttpMethod.POST, request, Map.class);

            if (response.getStatusCode().is2xxSuccessful() && response.getBody() != null) {
                logger.info("Successfully exchanged authorization code for tokens");
                @SuppressWarnings("unchecked")
                Map<String, Object> tokenResponse = response.getBody();
                return tokenResponse;
            } else {
                throw new RuntimeException("Token exchange failed with status: " + response.getStatusCode());
            }
        } catch (Exception e) {
            logger.error("Error exchanging authorization code", e);
            throw new RuntimeException("Token exchange failed: " + e.getMessage(), e);
        }
    }

    /**
     * Refresh an access token using a refresh token.
     */
    public Map<String, Object> refreshToken(String refreshToken, String registrationId) {
        ClientRegistration registration = clientRegistrationRepository.findByRegistrationId(registrationId);
        if (registration == null) {
            throw new IllegalArgumentException("Unknown registration: " + registrationId);
        }

        String tokenUri = registration.getProviderDetails().getTokenUri();
        String clientId = registration.getClientId();
        String clientSecret = registration.getClientSecret();

        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.APPLICATION_FORM_URLENCODED);

        String credentials = Base64.getEncoder().encodeToString((clientId + ":" + clientSecret).getBytes());
        headers.set("Authorization", "Basic " + credentials);

        MultiValueMap<String, String> body = new LinkedMultiValueMap<>();
        body.add("grant_type", "refresh_token");
        body.add("refresh_token", refreshToken);

        HttpEntity<MultiValueMap<String, String>> request = new HttpEntity<>(body, headers);

        logger.info("Refreshing token at endpoint: {}", tokenUri);

        try {
            @SuppressWarnings("unchecked")
            ResponseEntity<Map> response = restTemplate.exchange(tokenUri, HttpMethod.POST, request, Map.class);

            if (response.getStatusCode().is2xxSuccessful() && response.getBody() != null) {
                logger.info("Successfully refreshed token");
                @SuppressWarnings("unchecked")
                Map<String, Object> tokenResponse = response.getBody();
                return tokenResponse;
            } else {
                throw new RuntimeException("Token refresh failed with status: " + response.getStatusCode());
            }
        } catch (Exception e) {
            logger.error("Error refreshing token", e);
            throw new RuntimeException("Token refresh failed: " + e.getMessage(), e);
        }
    }

    /**
     * Fetch user info from the UserInfo endpoint.
     */
    public Map<String, Object> fetchUserInfo(String accessToken, String registrationId) {
        ClientRegistration registration = clientRegistrationRepository.findByRegistrationId(registrationId);
        if (registration == null) {
            throw new IllegalArgumentException("Unknown registration: " + registrationId);
        }

        String userInfoUri = registration.getProviderDetails().getUserInfoEndpoint().getUri();

        HttpHeaders headers = new HttpHeaders();
        headers.setBearerAuth(accessToken);

        HttpEntity<Void> request = new HttpEntity<>(headers);

        logger.info("Fetching user info from: {}", userInfoUri);

        try {
            @SuppressWarnings("unchecked")
            ResponseEntity<Map> response = restTemplate.exchange(userInfoUri, HttpMethod.GET, request, Map.class);

            if (response.getStatusCode().is2xxSuccessful() && response.getBody() != null) {
                logger.info("Successfully fetched user info");
                @SuppressWarnings("unchecked")
                Map<String, Object> userInfo = response.getBody();
                return userInfo;
            } else {
                throw new RuntimeException("UserInfo request failed with status: " + response.getStatusCode());
            }
        } catch (Exception e) {
            logger.error("Error fetching user info", e);
            throw new RuntimeException("UserInfo request failed: " + e.getMessage(), e);
        }
    }
}

