package com.example.oidcclient.handler;

import com.example.oidcclient.service.UserSessionService;
import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.core.Authentication;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.security.web.authentication.SavedRequestAwareAuthenticationSuccessHandler;
import org.springframework.stereotype.Component;

import java.io.IOException;

@Component
public class OidcAuthenticationSuccessHandler extends SavedRequestAwareAuthenticationSuccessHandler {

    private static final Logger logger = LoggerFactory.getLogger(OidcAuthenticationSuccessHandler.class);

    private final UserSessionService userSessionService;

    public OidcAuthenticationSuccessHandler(UserSessionService userSessionService) {
        this.userSessionService = userSessionService;
        setDefaultTargetUrl("/dashboard");
        setAlwaysUseDefaultTargetUrl(false);
    }

    @Override
    public void onAuthenticationSuccess(HttpServletRequest request, HttpServletResponse response,
                                         Authentication authentication) throws IOException, ServletException {

        if (authentication.getPrincipal() instanceof OidcUser oidcUser) {
            logger.info("OIDC authentication successful for user: {} ({})",
                oidcUser.getFullName(), oidcUser.getEmail());
            logger.debug("Authorities: {}", oidcUser.getAuthorities());
            logger.debug("Claims: {}", oidcUser.getClaims().keySet());

            // Store subject in HTTP session for correlation
            request.getSession().setAttribute("oidc_subject", oidcUser.getSubject());
        }

        super.onAuthenticationSuccess(request, response, authentication);
    }
}

// ============================================================
// Custom Logout Success Handler
// ============================================================
package com.example.oidcclient.handler;

import com.example.oidcclient.service.UserSessionService;
import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.core.Authentication;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.security.web.authentication.logout.SimpleUrlLogoutSuccessHandler;
import org.springframework.stereotype.Component;

import java.io.IOException;

@Component
public class OidcLogoutSuccessHandler extends SimpleUrlLogoutSuccessHandler {

    private static final Logger logger = LoggerFactory.getLogger(OidcLogoutSuccessHandler.class);

    private final UserSessionService userSessionService;

    public OidcLogoutSuccessHandler(UserSessionService userSessionService) {
        this.userSessionService = userSessionService;
        setDefaultTargetUrl("/");
    }

    @Override
    public void onLogoutSuccess(HttpServletRequest request, HttpServletResponse response,
                                 Authentication authentication) throws IOException, ServletException {

        if (authentication != null && authentication.getPrincipal() instanceof OidcUser oidcUser) {
            String subject = oidcUser.getSubject();
            userSessionService.removeSessionBySubject(subject);
            logger.info("User logged out and session removed for subject: {}", subject);
        }

        super.onLogoutSuccess(request, response, authentication);
    }
}

