// Session Cleanup Scheduler
// ============================================================
package com.example.oidcclient.config;

import com.example.oidcclient.service.UserSessionService;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.context.annotation.Configuration;
import org.springframework.scheduling.annotation.EnableScheduling;
import org.springframework.scheduling.annotation.Scheduled;

@Configuration
@EnableScheduling
public class SessionCleanupConfig {

    private static final Logger logger = LoggerFactory.getLogger(SessionCleanupConfig.class);

    private final UserSessionService userSessionService;

    public SessionCleanupConfig(UserSessionService userSessionService) {
        this.userSessionService = userSessionService;
    }

    @Scheduled(fixedRate = 300000) // every 5 minutes
    public void cleanupExpiredSessions() {
        logger.debug("Running session cleanup, active sessions: {}", userSessionService.getActiveSessionCount());
        userSessionService.cleanExpiredSessions();
    }
}

