package com.example.oidcclient.controller;

import com.example.oidcclient.model.UserSession;
import com.example.oidcclient.service.TokenExchangeService;
import com.example.oidcclient.service.UserSessionService;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;

import java.util.Optional;

@Controller
public class WebController {

    private static final Logger logger = LoggerFactory.getLogger(WebController.class);

    private final UserSessionService userSessionService;
    private final TokenExchangeService tokenExchangeService;

    public WebController(UserSessionService userSessionService,
                          TokenExchangeService tokenExchangeService) {
        this.userSessionService = userSessionService;
        this.tokenExchangeService = tokenExchangeService;
    }

    @GetMapping("/")
    public String home() {
        return "home";
    }

    @GetMapping("/login")
    public String login() {
        return "login";
    }

    @GetMapping("/dashboard")
    public String dashboard(@AuthenticationPrincipal OidcUser oidcUser, Model model) {
        if (oidcUser != null) {
            model.addAttribute("name", oidcUser.getFullName());
            model.addAttribute("email", oidcUser.getEmail());
            model.addAttribute("subject", oidcUser.getSubject());
            model.addAttribute("claims", oidcUser.getClaims());
            model.addAttribute("authorities", oidcUser.getAuthorities());
            model.addAttribute("idTokenValue", oidcUser.getIdToken().getTokenValue());

            // Fetch session info
            Optional<UserSession> session = userSessionService.getSessionBySubject(oidcUser.getSubject());
            session.ifPresent(s -> model.addAttribute("userSession", s));
        }
        return "dashboard";
    }

    @GetMapping("/profile")
    public String profile(@AuthenticationPrincipal OidcUser oidcUser, Model model) {
        if (oidcUser != null) {
            model.addAttribute("user", oidcUser);
            model.addAttribute("idToken", oidcUser.getIdToken());
            model.addAttribute("userInfo", oidcUser.getUserInfo());

            // Show all claims
            model.addAttribute("idTokenClaims", oidcUser.getIdToken().getClaims());
            if (oidcUser.getUserInfo() != null) {
                model.addAttribute("userInfoClaims", oidcUser.getUserInfo().getClaims());
            }
        }
        return "profile";
    }

    @GetMapping("/admin")
    public String admin(@AuthenticationPrincipal OidcUser oidcUser, Model model) {
        if (oidcUser != null) {
            model.addAttribute("user", oidcUser);
            model.addAttribute("activeSessionCount", userSessionService.getActiveSessionCount());
        }
        return "admin";
    }
}

// ============================================================
// REST API Controller
// ============================================================
package com.example.oidcclient.controller;

import com.example.oidcclient.model.UserSession;
import com.example.oidcclient.service.TokenExchangeService;
import com.example.oidcclient.service.UserSessionService;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.web.bind.annotation.*;

import java.util.HashMap;
import java.util.Map;
import java.util.Optional;

@RestController
@RequestMapping("/api")
public class ApiController {

    private final UserSessionService userSessionService;
    private final TokenExchangeService tokenExchangeService;

    public ApiController(UserSessionService userSessionService,
                          TokenExchangeService tokenExchangeService) {
        this.userSessionService = userSessionService;
        this.tokenExchangeService = tokenExchangeService;
    }

    @GetMapping("/me")
    public ResponseEntity<Map<String, Object>> currentUser(@AuthenticationPrincipal OidcUser oidcUser) {
        if (oidcUser == null) {
            return ResponseEntity.status(401).build();
        }

        Map<String, Object> userInfo = new HashMap<>();
        userInfo.put("subject", oidcUser.getSubject());
        userInfo.put("name", oidcUser.getFullName());
        userInfo.put("email", oidcUser.getEmail());
        userInfo.put("emailVerified", oidcUser.getEmailVerified());
        userInfo.put("picture", oidcUser.getPicture());
        userInfo.put("authorities", oidcUser.getAuthorities().stream()
            .map(Object::toString)
            .toList());

        return ResponseEntity.ok(userInfo);
    }

    @GetMapping("/session")
    public ResponseEntity<UserSession> sessionInfo(@AuthenticationPrincipal OidcUser oidcUser) {
        if (oidcUser == null) {
            return ResponseEntity.status(401).build();
        }

        Optional<UserSession> session = userSessionService.getSessionBySubject(oidcUser.getSubject());
        return session.map(ResponseEntity::ok)
            .orElseGet(() -> ResponseEntity.notFound().build());
    }

    @GetMapping("/claims")
    public ResponseEntity<Map<String, Object>> claims(@AuthenticationPrincipal OidcUser oidcUser) {
        if (oidcUser == null) {
            return ResponseEntity.status(401).build();
        }

        Map<String, Object> allClaims = new HashMap<>();
        allClaims.put("idTokenClaims", oidcUser.getIdToken().getClaims());
        if (oidcUser.getUserInfo() != null) {
            allClaims.put("userInfoClaims", oidcUser.getUserInfo().getClaims());
        }

        return ResponseEntity.ok(allClaims);
    }

    @PostMapping("/token/refresh")
    public ResponseEntity<Map<String, Object>> refreshToken(
            @AuthenticationPrincipal OidcUser oidcUser,
            @RequestParam String refreshToken) {
        if (oidcUser == null) {
            return ResponseEntity.status(401).build();
        }

        try {
            Map<String, Object> tokenResponse = tokenExchangeService.refreshToken(
                refreshToken, "oidc-provider");
            return ResponseEntity.ok(tokenResponse);
        } catch (Exception e) {
            Map<String, Object> error = new HashMap<>();
            error.put("error", "token_refresh_failed");
            error.put("message", e.getMessage());
            return ResponseEntity.badRequest().body(error);
        }
    }

    @GetMapping("/userinfo")
    public ResponseEntity<Map<String, Object>> userInfo(@AuthenticationPrincipal OidcUser oidcUser) {
        if (oidcUser == null) {
            return ResponseEntity.status(401).build();
        }

        try {
            Optional<UserSession> session = userSessionService.getSessionBySubject(oidcUser.getSubject());
            if (session.isPresent()) {
                Map<String, Object> userInfoResponse = tokenExchangeService.fetchUserInfo(
                    session.get().getAccessTokenValue(), "oidc-provider");
                return ResponseEntity.ok(userInfoResponse);
            }
            return ResponseEntity.notFound().build();
        } catch (Exception e) {
            Map<String, Object> error = new HashMap<>();
            error.put("error", "userinfo_fetch_failed");
            error.put("message", e.getMessage());
            return ResponseEntity.badRequest().body(error);
        }
    }
}

